INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8721d660-d224-44eb-b8d4-8b5e7ca50d12',
  '00000000-0000-0000-0000-000000000001',
  $escape$Hugging Face Transformers — Decoding LLM Sampling Strategies That Actually Matter$escape$,
  $escape$Every `model.generate()` call in Hugging Face Transformers is shaped by a handful of parameters that most developers misuse. Tokens are the atomic unit — `AutoTokenizer.from_pretrained()` encodes your string into token IDs, and the model never sees raw text. The `max_new_tokens` parameter controls output length independently of the prompt, unlike the deprecated `max_length` which counts the full sequence.

Context window is model-specific: `model.config.max_position_embeddings` gives you the hard limit. Exceeding it silently truncates or breaks positional encodings.

For sampling: `do_sample=False` uses greedy decoding (deterministic, picks highest logit). Enable `do_sample=True` to unlock `temperature` (scales logits before softmax — lower = sharper, higher = more uniform), `top_p` (nucleus sampling — cumulative probability cutoff), and `top_k` (restricts vocab to top-k tokens per step). These compose: `top_p=0.9, temperature=0.7` is the most common production pairing. `repetition_penalty > 1.0` discourages token repetition without touching the core distribution. Always pin `tokenizer.padding_side = 'left'` for batch generation.$escape$,
  $escape$from transformers import AutoTokenizer, AutoModelForCausalLM
import torch

tokenizer = AutoTokenizer.from_pretrained("meta-llama/Llama-3.2-1B-Instruct")
tokenizer.padding_side = "left"
model = AutoModelForCausalLM.from_pretrained("meta-llama/Llama-3.2-1B-Instruct", torch_dtype=torch.bfloat16)

print(f"Max context: {model.config.max_position_embeddings} tokens")

inputs = tokenizer("Explain attention in one sentence:", return_tensors="pt")

output = model.generate(
    **inputs,
    max_new_tokens=80,
    do_sample=True,
    temperature=0.7,
    top_p=0.9,
    repetition_penalty=1.1,
)
print(tokenizer.decode(output[0], skip_special_tokens=True))$escape$,
  $escape$python$escape$,
