INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a553bfbe-c137-47d0-8a5d-b21c6476a314',
  '00000000-0000-0000-0000-000000000001',
  $escape$HuggingFace Inference — Prompt Engineering with Chat Templates, Few-Shot, and Structured Output$escape$,
  $escape$HuggingFace chat models use tokenizer.apply_chat_template() to format prompts — skipping this is the #1 source of degraded outputs. System prompts go in the messages list as role: 'system', and the template handles special tokens (e.g. [INST], <|system|>) automatically per model family.

For few-shot prompting, inject role: 'user' / role: 'assistant' pairs before your actual query — the model learns the pattern in-context without fine-tuning.

Chain-of-thought is triggered by priming the assistant turn: append a partial role: 'assistant' message like 'Let me think step by step:' before generation. With InferenceClient, pass the messages list directly to chat_completion().

For structured output, use the response_format parameter in InferenceClient.chat_completion() with {'type': 'json_object'} — supported on hosted Inference Endpoints and serverless API. Pair with a system prompt that defines the exact JSON schema. For local pipelines, use outlines or guidance libraries with the transformers backend to enforce grammar-constrained decoding.$escape$,
  $escape$from huggingface_hub import InferenceClient

client = InferenceClient(model="meta-llama/Llama-3.3-70B-Instruct")

messages = [
    {"role": "system", "content": "Extract entities as JSON: {name, type, confidence}"},
    {"role": "user", "content": "Obama was born in Hawaii."},
    {"role": "assistant", "content": '{"name": "Obama", "type": "PERSON", "confidence": 0.99}'},
    {"role": "user", "content": "Apple released the M4 chip last year."},
]

response = client.chat_completion(
    messages=messages,
    response_format={"type": "json_object"},
    max_tokens=128,
)
print(response.choices[0].message.content)$escape$,
