INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '76d67327-60d1-448f-bc3f-cac8ed6b2425',
  '00000000-0000-0000-0000-000000000001',
  $escape$HuggingFace + LangChain LCEL — Building Chains with HuggingFaceEndpoint$escape$,
  $escape$LangChain's LCEL pipe syntax works seamlessly with `langchain_huggingface`, letting you compose HuggingFace-backed chains without boilerplate. The key distinction: `HuggingFaceEndpoint` hits the Inference API (no local GPU needed), while `HuggingFacePipeline` wraps a locally-loaded `transformers` pipeline — choose based on latency vs. cost tradeoffs.

LCEL chains are `Runnable` objects, so every `|` step is lazy, streamable, and batchable by default. `chain.stream()` works out of the box with `HuggingFaceEndpoint` for token-by-token output. For memory, wrap your chain in `RunnableWithMessageHistory`, passing a `ChatMessageHistory` instance keyed by `session_id` — this replaces the deprecated `ConversationChain`.

For agents, use `create_react_agent` with a HuggingFace model that supports tool-calling (e.g., `Qwen/Qwen2.5-72B-Instruct` or `mistralai/Mistral-7B-Instruct-v0.3` via Inference API). Bind tools directly with `llm.bind_tools([...])` before piping into your agent executor. Avoid `initialize_agent` — it's legacy and doesn't compose with LCEL.$escape$,
  $escape$from langchain_huggingface import HuggingFaceEndpoint
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser
from langchain_core.runnables.history import RunnableWithMessageHistory
from langchain_community.chat_message_histories import ChatMessageHistory

llm = HuggingFaceEndpoint(
    repo_id="mistralai/Mistral-7B-Instruct-v0.3",
    task="text-generation",
    max_new_tokens=512,
)

prompt = ChatPromptTemplate.from_messages([
    ("system", "You are a concise technical assistant."),
    ("placeholder", "{history}"),
    ("human", "{question}"),
])

chain = prompt | llm | StrOutputParser()

store = {}
chain_with_memory = RunnableWithMessageHistory(
    chain,
    lambda sid: store.setdefault(sid, ChatMessageHistory()),
    input_messages_key="question",
    history_messages_key="history",
)

for chunk in chain_with_memory.stream(
    {"question": "What is grouped-query attention?"},
    config={"configurable": {"session_id": "dev-1"}},
):
    print(chunk, end="", flush=True)$escape$,
  $escape$python$escape$,
