INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3e4e8001-487f-4b7d-84e0-f694674990fc',
  '00000000-0000-0000-0000-000000000001',
  $escape$HuggingFace + LlamaIndex — Building RAG Pipelines with HuggingFaceEmbedding and Custom Retrievers$escape$,
  $escape$LlamaIndex integrates tightly with HuggingFace through `HuggingFaceEmbedding` and `HuggingFaceLLM`, letting you build fully local RAG pipelines without OpenAI. For document loading, use `SimpleDirectoryReader` or `HuggingFaceDatasetReader` to pull datasets directly from the Hub via `datasets` under the hood. Indexing strategy matters: `VectorStoreIndex` stores embeddings using your chosen HF model (e.g. `BAAI/bge-small-en-v1.5`), while `SummaryIndex` chains nodes for long-context summarization. Set `embed_model` globally via `Settings.embed_model` to avoid passing it per-call. For retrieval, `VectorIndexRetriever` with `similarity_top_k` controls recall; pair it with `SentenceTransformerRerank` (also HF-backed) as a `RetrieverQueryEngine` postprocessor to boost precision. Crucially, `HuggingFaceLLM` wraps any `AutoModelForCausalLM` — set `context_window` and `max_new_tokens` to match your model's limits or you'll silently truncate context. Use `RetrieverQueryEngine.from_args(retriever, node_postprocessors=[reranker])` to compose the full pipeline declaratively.$escape$,
  $escape$from llama_index.core import VectorStoreIndex, Settings
from llama_index.embeddings.huggingface import HuggingFaceEmbedding
from llama_index.llms.huggingface import HuggingFaceLLM
from llama_index.core.postprocessor import SentenceTransformerRerank
from llama_index.core.query_engine import RetrieverQueryEngine
from llama_index.readers.huggingface_fs import HuggingFaceDatasetReader

Settings.embed_model = HuggingFaceEmbedding(model_name="BAAI/bge-small-en-v1.5")
Settings.llm = HuggingFaceLLM(model_name="HuggingFaceH4/zephyr-7b-beta", context_window=3900, max_new_tokens=512)

reader = HuggingFaceDatasetReader(dataset_name="rajpurkar/squad", split="train[:500]")
docs = reader.load_data()
index = VectorStoreIndex.from_documents(docs)

retriever = index.as_retriever(similarity_top_k=5)
reranker = SentenceTransformerRerank(model="cross-encoder/ms-marco-MiniLM-L-6-v2", top_n=3)
engine = RetrieverQueryEngine.from_args(retriever, node_postprocessors=[reranker])
print(engine.query("What is the capital of France?"))$escape$,
  $escape$python$escape$,
