INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6d98628c-b0e5-468b-8528-75295289f98d',
  '00000000-0000-0000-0000-000000000001',
  $escape$HuggingFace RAG Pipeline — Chunking, Embedding, Retrieval, and Reranking$escape$,
  $escape$Building a production RAG pipeline with HuggingFace requires deliberate choices at each stage. For chunking, use `langchain`'s `RecursiveCharacterTextSplitter` with `chunk_size=512` and `chunk_overlap=64` — overlap prevents context loss at boundaries. Feed chunks into `sentence-transformers/all-MiniLM-L6-v2` via `SentenceTransformer.encode()` for dense embeddings; store them in FAISS using `faiss.IndexFlatIP` for cosine similarity (normalize vectors first with `util.normalize_embeddings`). At retrieval, fetch top-k=20 candidates — cast a wide net because your reranker will filter aggressively. Reranking is where HuggingFace shines: use `cross-encoder/ms-marco-MiniLM-L-6-v2` via `CrossEncoder.predict([(query, doc), ...])` to score each candidate pair. This cross-attention model dramatically outperforms bi-encoder retrieval alone. Finally, pass your top-3 reranked passages into your LLM context window. The `FlagEmbeddingReranker` from `ragatouille` wraps this cleanly if you need a higher-level API. Avoid embedding your query at rerank time — cross-encoders take the raw string pair directly.$escape$,
  $escape$from sentence_transformers import SentenceTransformer, CrossEncoder, util
import faiss, numpy as np

bi_encoder = SentenceTransformer('sentence-transformers/all-MiniLM-L6-v2')
cross_encoder = CrossEncoder('cross-encoder/ms-marco-MiniLM-L-6-v2')

# Embed and index corpus
corpus_embeddings = bi_encoder.encode(chunks, normalize_embeddings=True, convert_to_numpy=True)
index = faiss.IndexFlatIP(corpus_embeddings.shape[1])
index.add(corpus_embeddings)

# Retrieve top-20, rerank to top-3
query_vec = bi_encoder.encode([query], normalize_embeddings=True, convert_to_numpy=True)
_, I = index.search(query_vec, k=20)
candidates = [chunks[i] for i in I[0]]
scores = cross_encoder.predict([(query, c) for c in candidates])
top3 = [candidates[i] for i in np.argsort(scores)[::-1][:3]]$escape$,
  $escape$python$escape$,
