INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8dad2017-955d-4df5-b0b4-12321529e78c',
  '00000000-0000-0000-0000-000000000001',
  $escape$HuggingFace InferenceClient — Accessing Claude with System Prompts, Tools, and Streaming$escape$,
  $escape$HuggingFace's `InferenceClient` supports Anthropic's Claude models natively via `provider="anthropic"`, letting you route to Claude without leaving the HuggingFace SDK. Pass your Anthropic API key directly — HuggingFace acts as a thin routing layer, preserving the familiar `chat_completion` interface you use with open-source models.

System prompts map to the `system` parameter on `chat_completion` (not a message role). Tool use follows the OpenAI-compatible schema HuggingFace normalizes across providers: define tools as JSON schemas, set `tool_choice="auto"`, and inspect `response.choices[0].message.tool_calls`. Streaming works identically to other providers — pass `stream=True` and iterate the generator, reading `chunk.choices[0].delta.content`.

The key leverage: you can swap `model="claude-opus-4-5"` for `model="meta-llama/Llama-3.3-70B-Instruct"` and `provider="together"` with zero interface changes. This makes Claude a drop-in for HuggingFace inference pipelines during evals or production A/B testing — no Anthropic SDK import, no separate client initialization.$escape$,
  $escape$from huggingface_hub import InferenceClient

client = InferenceClient(provider="anthropic", api_key="sk-ant-...")

tools = [{
    "type": "function",
    "function": {
        "name": "search_hub",
        "description": "Search HuggingFace Hub for models",
        "parameters": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]}
    }
}]

for chunk in client.chat_completion(
    model="claude-opus-4-5",
    messages=[{"role": "user", "content": "Find a small embedding model on the Hub."}],
    system="You are a HuggingFace model discovery assistant.",
    tools=tools,
    tool_choice="auto",
    stream=True,
    max_tokens=300,
):
    print(chunk.choices[0].delta.content or "", end="", flush=True)$escape$,
  $escape$python$escape$,
