INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2fd68442-604f-42f3-9c30-1fd480d37ffb',
  '00000000-0000-0000-0000-000000000001',
  $escape$HuggingFace InferenceClient + Groq — Sub-100ms Inference Without Changing Your Call Signature$escape$,
  $escape$Groq's LPU (Language Processing Unit) delivers sub-100ms time-to-first-token for large models — a 10–20× throughput gain over GPU-based inference. HuggingFace's `InferenceClient` natively supports Groq as a `provider`, so you can swap backends without touching your call signature.

Models available via Groq on HuggingFace Hub include `meta-llama/Llama-3.3-70B-Instruct`, `mistralai/Mixtral-8x7B-Instruct-v0.1`, and `google/gemma-2-9b-it` — all addressable by their HF repo ID. `InferenceClient` routes requests to Groq's API under the hood while keeping HF's unified interface.

One gotcha: not every HF model ID maps to a Groq-hosted model. Use `InferenceClient(provider="groq").list_deployed_models()` to see what's live before hardcoding a model slug.

For streaming, pass `stream=True` to `chat.completions.create()` — the response becomes an iterator of `ChatCompletionStreamOutput` chunks, identical to the standard HF streaming interface. Free-tier rate limits are generous for prototyping but cap at ~30 req/min for 70B-class models.$escape$,
  $escape$from huggingface_hub import InferenceClient

client = InferenceClient(
    provider="groq",
    api_key="gsk_YOUR_GROQ_KEY",
)

# Stream tokens from Llama 3.3 70B via Groq's LPU
for chunk in client.chat.completions.create(
    model="meta-llama/Llama-3.3-70B-Instruct",
    messages=[{"role": "user", "content": "Explain RLHF in 2 sentences."}],
    stream=True,
):
    print(chunk.choices[0].delta.content, end="", flush=True)$escape$,
  $escape$python$escape$,
