INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b3f6b1df-804a-4fdb-8086-4ca6b042e266',
  '00000000-0000-0000-0000-000000000001',
  $escape$HuggingFace + Ollama — Serve Any Hub GGUF Model Locally, Zero API Calls$escape$,
  $escape$Ollama's native HuggingFace Hub integration lets you pull any GGUF model directly using the `hf.co/<user>/<repo>:<quant>` namespace — no manual downloads or Modelfile authoring. Run `ollama pull hf.co/bartowski/Llama-3.2-3B-Instruct-GGUF:Q4_K_M` and the model is ready in seconds. Privacy-wise, inference never leaves your machine — no tokens forwarded to Groq, OpenAI, or HF's own Inference API.

The real power for HuggingFace users: `huggingface_hub.InferenceClient` speaks the OpenAI-compatible protocol, and Ollama exposes exactly that at `localhost:11434/v1`. Point `base_url` there and your existing `chat_completion()` calls work unchanged — swap between HF's serverless Inference API and local Ollama by changing one URL. Develop and test locally with full data privacy, then point at HF Inference Endpoints for production without touching business logic.

For model discovery, HF Hub's `gguf` and `ollama` search tags surface community-quantized checkpoints of Llama 3.2, Mistral, Phi-3, and more — often within hours of a model's upstream release.$escape$,
  $escape$from huggingface_hub import InferenceClient

# First: ollama pull hf.co/bartowski/Llama-3.2-3B-Instruct-GGUF:Q4_K_M

client = InferenceClient(
    model="hf.co/bartowski/Llama-3.2-3B-Instruct-GGUF:Q4_K_M",
    base_url="http://localhost:11434/v1",
    api_key="ollama",  # required by client; ignored by Ollama
)

response = client.chat_completion(
    messages=[{"role": "user", "content": "Explain RLHF in one paragraph."}],
    max_tokens=256,
)
print(response.choices[0].message.content)$escape$,
  $escape$python$escape$,
