INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '96e508bb-784d-4b7f-9c16-4a3b15c71c04',
  '00000000-0000-0000-0000-000000000001',
  $escape$HuggingFace Sentence Transformers — Choosing the Right Embedding Model for Semantic Similarity$escape$,
  $escape$Not all embedding models on HuggingFace Hub are equal for semantic similarity tasks. `sentence-transformers/all-MiniLM-L6-v2` is the go-to for speed (384-dim, ~80MB), but `BAAI/bge-large-en-v1.5` consistently outperforms it on MTEB benchmarks for retrieval tasks. The key difference: BGE models are trained with instruction prefixes — prepend `"Represent this sentence for searching relevant passages: "` to queries (not corpus documents) or similarity degrades measurably.

Use `SentenceTransformer.encode()` with `normalize_embeddings=True` to get unit-norm vectors, enabling cosine similarity via simple dot product — no need for `sklearn`. For large corpora, `encode()` accepts `batch_size` and `show_progress_bar` params and handles padding/truncation internally via the underlying tokenizer.

To compare models without switching code, swap the model string — the `SentenceTransformer` API is model-agnostic across all `sentence-transformers`-compatible checkpoints on Hub. Use `util.semantic_search()` for top-k retrieval with built-in cosine scoring instead of rolling your own.$escape$,
  $escape$from sentence_transformers import SentenceTransformer, util

# BGE requires instruction prefix on queries, not corpus docs
model = SentenceTransformer("BAAI/bge-large-en-v1.5")

query = "Represent this sentence for searching relevant passages: how do transformers handle long sequences?"
corpus = [
    "Transformers use attention mechanisms that scale quadratically with sequence length.",
    "Python lists are ordered and mutable collections.",
    "Longformer replaces full attention with sliding window attention for long documents.",
]

query_emb = model.encode(query, normalize_embeddings=True)
corpus_embs = model.encode(corpus, normalize_embeddings=True, batch_size=32)

results = util.semantic_search(query_emb, corpus_embs, top_k=2)
for hit in results[0]:
    print(f"Score: {hit['score']:.4f} | {corpus[hit['corpus_id']]}")$escape$,
  $escape$python$escape$,
