INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2fcf9c22-ce95-4ced-b5f9-7ae8a967fa43',
  '00000000-0000-0000-0000-000000000001',
  $escape$HuggingFace smolagents — Building ReAct Agents with Custom Tools$escape$,
  $escape$HuggingFace's `smolagents` library implements the ReAct (Reason + Act) pattern natively. Agents alternate between Thought, Action, and Observation steps until a task resolves. Two agent types exist: `ToolCallingAgent` (structured JSON tool calls) and `CodeAgent` (generates + executes Python directly — more flexible, higher risk).

Define tools with the `@tool` decorator — smolagents injects the docstring as the tool description into the model's context, so write it precisely. Tool selection happens via the model's own reasoning; the agent sees all tool signatures and picks based on the task. The `agent.run()` loop handles retries and error recovery automatically.

Use `HfApiModel` to back the agent with any Inference API model, or `LiteLLMModel` for OpenAI-compatible endpoints. For multi-agent setups, `ManagedAgent` wraps any agent as a callable tool — enabling hierarchical orchestration without custom glue code. Max steps is configurable via `max_steps` to prevent runaway loops.$escape$,
  $escape$from smolagents import CodeAgent, HfApiModel, tool

@tool
def get_repo_stars(repo_id: str) -> int:
    """Returns the star count for a HuggingFace Hub repository."""
    from huggingface_hub import repo_info
    return repo_info(repo_id).likes

model = HfApiModel(model_id="Qwen/Qwen2.5-Coder-32B-Instruct")
agent = CodeAgent(
    tools=[get_repo_stars],
    model=model,
    max_steps=5
)

result = agent.run("Which has more stars: 'meta-llama/Llama-3.1-8B' or 'mistralai/Mistral-7B-v0.1'?")
print(result)$escape$,
  $escape$python$escape$,
