INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '238c7cb6-9ccd-48dd-ae73-c7ea274f6643',
  '00000000-0000-0000-0000-000000000001',
  $escape$HuggingFace Safety & Guardrails — Filtering Outputs, Blocking Prompt Injection, and Reducing Hallucinations$escape$,
  $escape$HuggingFace's ecosystem offers layered guardrails you can wire directly into your inference pipeline. For output filtering, `transformers-interpret` and the `Detoxify` model (`unitary/toxic-bert`) classify generated text before it reaches users — pipe your generation output through a zero-shot classification head using `pipeline('text-classification', model='unitary/toxic-bert')` and gate on the score. For prompt injection, use `meta-llama/Prompt-Guard-86M`, a dedicated classifier trained to detect jailbreaks and injection patterns — run it on raw user input before forwarding to your LLM. For hallucination mitigation, pair your generation model with `vectara/hallucination_evaluation_model`, a cross-encoder that scores faithfulness between a claim and its source passages; integrate it as a post-generation validator. Combine these into a single `Pipeline` subclass that overrides `__call__` to enforce pre- and post-generation checks. On Inference Endpoints, deploy each guard as a sidecar or use HuggingFace's `SafeTextGenerationPipeline` pattern to keep latency predictable. All three models are available on the Hub and run on CPU for low-throughput use cases.$escape$,
  $escape$from transformers import pipeline

# Guard 1: Prompt injection detection
injection_guard = pipeline('text-classification', model='meta-llama/Prompt-Guard-86M')

# Guard 2: Main generation
generator = pipeline('text-generation', model='mistralai/Mistral-7B-Instruct-v0.3')

# Guard 3: Toxicity filter on output
toxicity_filter = pipeline('text-classification', model='unitary/toxic-bert')

def safe_generate(user_prompt: str) -> str:
    if injection_guard(user_prompt)[0]['label'] == 'INJECTION':
        raise ValueError('Prompt injection detected')
    output = generator(user_prompt, max_new_tokens=256)[0]['generated_text']
    if toxicity_filter(output)[0]['score'] > 0.85:
        return '[Response withheld: policy violation]'
    return output$escape$,
  $escape$python$escape$,
